// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const conditionIcon = useMemo(() => {
    const cond = props.condition.toLowerCase();
    if (cond.includes('sunny')) return 'sun';
    if (cond.includes('rain')) return 'cloud-rain';
    if (cond.includes('cloud')) return 'cloud';
    return 'cloud-sun';
  }, [props.condition]);

  return { conditionIcon };
}

export default function Component(props: Props) {
  const { conditionIcon } = useComponent(props);

  return (
    <Card padding={24} radius="xl" shadow="md">
      <Stack gap={24}>
        <Row justify="between" align="center">
          <Heading level={3}>{props.city}</Heading>
          <Badge variant="primary">{props.condition}</Badge>
        </Row>
        <Stack align="center" gap={8}>
          <Heading level={1} color="var(--ggui-color-primary-600)">{props.temperature}°{props.unit}</Heading>
          <Icon name={conditionIcon} size={48} color="var(--ggui-color-onSurfaceVariant)" />
        </Stack>
        <Row justify="evenly">
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="bodyLarge">{props.humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind</Text>
            <Text variant="bodyLarge">{props.windSpeed} km/h</Text>
          </Stack>
        </Row>
        <Divider />
        <Row justify="between">
          {props.forecast.map((f, i) => (
            <Stack key={i} align="center" gap={8}>
              <Text variant="caption" weight="medium">{f.day}</Text>
              <Icon name={f.icon || 'sun'} size={20} />
              <Text variant="caption">{f.high}°/{f.low}°</Text>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (data: Record<string, unknown>) => void; // Action: Submit Survey
}

function useComponent(props: Props) {
  const handleSubmit = useCallback((data: Record<string, unknown>) => {
    props.onSubmit?.(data);
  }, [props.onSubmit]);

  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    interests: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = useMemo(() => {
    if (step === 0) return formData.name.trim() !== '' && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const checkEmailOnBlur = useCallback(() => {
    setErrors(prev => ({ ...prev, email: validateEmail(formData.email) ? '' : 'Invalid email format' }));
  }, [formData.email]);

  const nextStep = useCallback(() => setStep(s => Math.min(s + 1, 4)), []);
  const prevStep = useCallback(() => setStep(s => Math.max(s - 1, 0)), []);

  return { step, formData, setFormData, errors, setErrors, isStepValid, nextStep, prevStep, handleSubmit };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, errors, setErrors, isStepValid, nextStep, prevStep, handleSubmit } = useComponent(props);

  const updateField = (key: string, value: any) => setFormData(d => ({ ...d, [key]: value }));

  return (
    <Container maxWidth="md" padding="24px">
      <Stack gap={16}>
        <Progress value={step} max={4} variant="default" showLabel={false} />
        <Heading level={2}>{step === 4 ? 'Review & Submit' : `Step ${step + 1} of 4`}</Heading>

        <Card padding={24}>
          {step === 0 && (
            <Stack gap={16}>
              <Input label="Name" value={formData.name} onChange={(v) => updateField('name', v)} required />
              <Input 
                label="Email" 
                type="email" 
                value={formData.email} 
                onChange={(v) => { updateField('email', v); if(errors.email) setErrors(p=>({...p, email:''})) }} 
                onBlur={() => setErrors(p=>({...p, email: !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) ? 'Invalid email format' : ''}))}
                required 
                error={errors.email} 
              />
            </Stack>
          )}
          {step === 1 && (
            <RadioGroup label="Satisfaction Rating" value={formData.satisfaction} onChange={(v) => updateField('satisfaction', v)} options={props.satisfactionLabels.map((l, i) => ({ value: (i+1).toString(), label: l }))} />
          )}
          {step === 2 && (
            <Stack gap={8}>
              <Text variant="label">Feature Interests</Text>
              {props.featureOptions.map(f => (
                <Checkbox key={f} label={f} checked={formData.interests.includes(f)} onChange={(checked) => updateField('interests', checked ? [...formData.interests, f] : formData.interests.filter(i => i !== f))} />
              ))}
            </Stack>
          )}
          {step === 3 && (
            <TextArea label="Comments (Optional)" value={formData.comments} onChange={(v) => updateField('comments', v)} maxLength={500} showCount />
          )}
          {step === 4 && (
            <Stack gap={12}>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {formData.satisfaction}</Text>
              <Text>Interests: {formData.interests.join(', ')}</Text>
              <Text>Comments: {formData.comments}</Text>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="outline" onClick={prevStep} disabled={step === 0}>Back</Button>
          {step < 3 ? (
            <Button onClick={nextStep} disabled={!isStepValid}>Next</Button>
          ) : <Button variant="primary" onClick={step === 3 ? nextStep : () => handleSubmit(formData)} disabled={!isStepValid}>{step === 3 ? 'Review' : 'Submit'}</Button>}
        </Row>
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const columns = props.columns || [];

  const stats = useMemo(() => ({
    total: tasks.length,
    completed: tasks.filter(t => t.column === 'done').length,
  }), [tasks]);

  const addTask = useCallback((columnId: string) => {
    const newTask = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      priority: newPriority as 'low' | 'medium' | 'high',
      column: columnId,
      assignee: 'JD',
      dueDate: new Date().toISOString().split('T')[0],
    };
    setTasks([...tasks, newTask]);
    setAddingToColumn(null);
    setNewTitle('');
    handleTaskUpdate({ action: 'create', task: newTask });
  }, [tasks, newTitle, newPriority, handleTaskUpdate]);

  const updateTask = useCallback((taskId: string, updates: Record<string, any>) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, ...updates } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ action: 'update', taskId, updates });
    setEditingTaskId(null);
  }, [tasks, handleTaskUpdate]);

  const moveTask = useCallback((taskId: string, targetColumn: string) => {
    const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setTasks(updatedTasks);
    handleTaskUpdate({ action: 'move', taskId, targetColumn });
  }, [tasks, handleTaskUpdate]);

  return { tasks, columns, addingToColumn, setAddingToColumn, newTitle, setNewTitle, newPriority, setNewPriority, editingTaskId, setEditingTaskId, addTask, updateTask, moveTask, stats };
}

export default function Component(props: Props) {
  const { tasks, columns, addingToColumn, setAddingToColumn, newTitle, setNewTitle, newPriority, setNewPriority, editingTaskId, setEditingTaskId, addTask, updateTask, moveTask, stats } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={2}>Project Board</Heading>
          <Stack direction="horizontal" gap={8}>
            <Badge variant="primary">{stats.total} Tasks</Badge>
            <Badge variant="success">{stats.completed} Done</Badge>
          </Stack>
        </Row>
        <Row gap={16} align="start">
          {columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" borderRadius={12} padding={16} style={{ flex: 1, minWidth: 280 }} role="region" aria-labelledby={`col-heading-${col.id}`}>
              <Stack gap={12}>
                <Row justify="between" align="center">
                  <Heading level={5} id={`col-heading-${col.id}`}>{col.name}</Heading>
                  <Badge size="sm">{tasks.filter(t => t.column === col.id).length}</Badge>
                </Row>
                <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                  <Stack gap={8}>
                    {tasks.filter(t => t.column === col.id).map(task => (
                      <li key={task.id}>
                        <Card padding={12} shadow="sm">
                          <Stack gap={8}>
                            <Row justify="between" align="start">
                              {editingTaskId === task.id ? (
                                <Input value={task.title} onChange={(val) => updateTask(task.id!, { title: val })} />
                              ) : (
                                <Text variant="body" weight="medium">{task.title}</Text>
                              )}
                              <Dropdown
                                trigger={<Button variant="ghost" size="xs" aria-label="Move task">...</Button>}
                                options={columns.filter(c => c.id !== col.id).map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                                onChange={(targetCol) => moveTask(task.id!, targetCol)}
                              />
                            </Row>
                            <Row justify="between" align="center">
                              <Stack direction="horizontal" gap={4} align="center">
                                <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'} size="sm">
                                  {task.priority?.toUpperCase()}
                                </Badge>
                                {task.dueDate && (
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    📅 {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                                  </Text>
                                )}
                              </Stack>
                              <Avatar name={task.assignee || '??'} size={24} />
                            </Row>
                          </Stack>
                        </Card>
                      </li>
                    ))}
                  </Stack>
                </ul>
                {addingToColumn === col.id ? (
                  <Stack gap={8}>
                    <Input label="Title" value={newTitle} onChange={setNewTitle} placeholder="Task title" />
                    <Select label="Priority" value={newPriority} onChange={setNewPriority} options={[
                      { value: 'low', label: 'Low' },
                      { value: 'medium', label: 'Medium' },
                      { value: 'high', label: 'High' }
                    ]} />
                    <Row gap={8}>
                      <Button onClick={() => addTask(col.id!)} aria-label="Confirm add task">Add</Button>
                      <Button variant="ghost" onClick={() => setAddingToColumn(null)} aria-label="Cancel">Cancel</Button>
                    </Row>
                  </Stack>
                ) : (
                  <Button variant="ghost" fullWidth onClick={() => setAddingToColumn(col.id!)} aria-label={`Add task to ${col.name}`}>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const CATEGORY_COLORS: Record<string, string> = {
    'Noble Gas': 'var(--ggui-color-info-200)',
    'Halogen': 'var(--ggui-color-warning-200)',
    'Alkali Metal': 'var(--ggui-color-error-200)',
    'Alkaline Earth Metal': 'var(--ggui-color-primary-200)',
    'Transition Metal': 'var(--ggui-color-primary-100)',
    'Post-Transition Metal': 'var(--ggui-color-surfaceVariant)',
    'Metalloid': 'var(--ggui-color-success-100)',
    'Non-metal': 'var(--ggui-color-surfaceVariant)',
    'Lanthanide': 'var(--ggui-color-info-100)',
    'Actinide': 'var(--ggui-color-warning-100)',
  };

  const getCategoryColor = (category?: string) => {
    return CATEGORY_COLORS[category || ''] || 'var(--ggui-color-surfaceVariant)';
  };

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category || 'Unknown'))), [props.elements]);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(e => 
      e.name?.toLowerCase().includes(q) || 
      e.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  const handleElementClick = useCallback((element: Props['elements'][0]) => {
    setSelectedElement(element);
  }, []);

  return { searchQuery, setSearchQuery, selectedElement, setSelectedElement, categories, filteredElements, handleElementClick };
}

export default function Component(props: Props) {
  const { searchQuery, setSearchQuery, selectedElement, setSelectedElement, categories, filteredElements, handleElementClick } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-8)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>
        <SearchField value={searchQuery} onChange={setSearchQuery} placeholder="Search by name or symbol..." />

        <Row gap="var(--ggui-spacing-2)" wrap>
          {categories.map(cat => <Tag key={cat} style={{ background: getCategoryColor(cat) }}>{cat}</Tag>)}
        </Row>

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {filteredElements.map(el => (
            <Card 
              key={el.symbol} 
              as={Clickable}
              onClick={() => handleElementClick(el)}
              shadow="sm"
              padding="var(--ggui-spacing-1)"
              aria-label={`Element ${el.name}, Atomic Number ${el.atomicNumber}, Category ${el.category}`}
              style={{ 
                gridColumn: el.col, 
                gridRow: el.row,
                aspectRatio: '1',
                background: getCategoryColor(el.category)
              }}
            >
              <Stack gap={0} align="center" justify="center" style={{ height: '100%' }}>
                <Text variant="caption" style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}>{el.atomicNumber}</Text>
                <Heading level={4}>{el.symbol}</Heading>
              </Stack>
            </Card>
          ))}
        </Box>

        <Modal open={!!selectedElement} onClose={() => setSelectedElement(null)} title="Element Details">
          {selectedElement && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
              <Stack direction="horizontal" gap="var(--ggui-spacing-4)">
                <Box>
                  <Text variant="label">Atomic Number</Text>
                  <Text>{selectedElement.atomicNumber}</Text>
                </Box>
                <Box>
                  <Text variant="label">Atomic Weight</Text>
                  <Text>{selectedElement.atomicWeight}</Text>
                </Box>
              </Stack>
              <Box>
                <Text variant="label">Category</Text>
                <Text>{selectedElement.category}</Text>
              </Box>
              <Button onClick={() => setSelectedElement(null)}>Close</Button>
            </Stack>
          )}
        </Modal>
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = props.product?.stock || 0;
  const isOutOfStock = stock === 0;
  const isLowStock = stock > 0 && stock <= 5;

  const increment = useCallback(() => setQuantity(q => Math.min(q + 1, stock)), [stock]);
  const decrement = useCallback(() => setQuantity(q => Math.max(q - 1, 1)), []);

  const onAddToCart = useCallback(() => {
    props.onAddToCart?.({ productId: props.product?.id, quantity });
  }, [props.onAddToCart, props.product?.id, quantity]);

  return { quantity, activeTab, setActiveTab, increment, decrement, onAddToCart, isOutOfStock, isLowStock };
}

export default function Component(props: Props) {
  const { quantity, activeTab, setActiveTab, increment, decrement, onAddToCart, isOutOfStock, isLowStock } = useComponent(props);
  const { product } = props;

  if (!product) return null;

  return (
    <Container maxWidth="xl" padding="24px">
      <Stack gap={24}>
        <Row gap={24} align="start" wrap={true}>
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)" padding="48px" style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">{product.name} Image</Text>
          </Box>
          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{product.name}</Heading>
            <Text variant="bodyLarge">{product.currency}{product.price}</Text>
            <Row gap={4}>
              {[1, 2, 3, 4, 5].map(i => (
                <Icon key={i} name={i <= (product.rating || 0) ? 'star' : 'star-outline'} color={i <= (product.rating || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'} size={20} />
              ))}
            </Row>
            <Badge variant={isOutOfStock ? 'error' : (isLowStock ? 'warning' : 'success')}>
              {isOutOfStock ? 'Out of Stock' : (isLowStock ? 'Low Stock' : 'In Stock')}
            </Badge>
            <Divider />
            <Row gap={16} align="center">
              <Row gap={8} align="center">
                <Button size="sm" variant="secondary" onClick={decrement} disabled={quantity <= 1} aria-label="Decrease quantity">-</Button>
                <Text variant="label">{quantity}</Text>
                <Button size="sm" variant="secondary" onClick={increment} disabled={quantity >= (product.stock || 0)} aria-label="Increase quantity">+</Button>
              </Row>
              <Button variant="primary" onClick={onAddToCart} disabled={isOutOfStock}>Add to Cart</Button>
            </Row>
          </Stack>
        </Row>

        <Tabs
          variant="line"
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: <Text variant="body">{product.description}</Text>
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Table
                  columns={[
