  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email), [formData.email]);
  const isStep1Valid = !!formData.name && isEmailValid;
  const isStep2Valid = !!formData.role;

  const handleNext = useCallback(() => setStep((s) => Math.min(s + 1, 3)), []);
  const handleBack = useCallback(() => setStep((s) => Math.max(s - 1, 1)), []);

  const submit = useCallback(() => {
    handleComplete(formData);
  }, [formData, handleComplete]);

  return { step, formData, setFormData, isStep1Valid, isStep2Valid, handleNext, handleBack, submit };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, isStep1Valid, isStep2Valid, handleNext, handleBack, submit } = useComponent(props);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <Card padding={32} shadow="md" radius="xl" border={true}>
        <Stack gap="var(--ggui-spacing-8)">
          <Box>
            <Heading level={2} align="center">Welcome Aboard</Heading>
            <Spacer size={24} />
            <Progress value={(step / 3) * 100} size="sm" variant="default" />
            <Spacer size={12} />
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">Step {step} of 3</Text>
          </Box>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Profile Setup</Heading>
              <Input label="Name" value={formData.name} onChange={(name) => setFormData({ ...formData, name })} required />
              <Input label="Email" type="email" value={formData.email} onChange={(email) => setFormData({ ...formData, email })} required error={formData.email && !isEmailValid ? 'Invalid email format' : undefined} />
              <Stack gap="var(--ggui-spacing-4)">
                <Text variant="label">Select Avatar</Text>
                <Row gap="var(--ggui-spacing-4)">
                  {props.avatarOptions.map((a) => (
                    <Box as={Clickable} key={a} onClick={() => setFormData({ ...formData, avatar: a })} 
                      paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-md)"
                      background={formData.avatar === a ? 'var(--ggui-color-primary-50)' : 'transparent'}
                      style={{ border: `2px solid ${formData.avatar === a ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)'}`, transition: 'all 0.2s' }}>
                      <Text size="2xl">{a}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={formData.role} onChange={(role) => setFormData({ ...formData, role })} options={props.roleOptions.map(r => ({ value: r, label: r }))} required placeholder="Select a role" />
              <Divider />
              <Checkbox label="Email Notifications" description="Receive updates about your account" checked={formData.emailNotifications} onChange={(emailNotifications) => setFormData({ ...formData, emailNotifications })} />
              <Toggle label={formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'} checked={formData.theme === 'dark'} onChange={(dark) => setFormData({ ...formData, theme: dark ? 'dark' : 'light' })} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Review & Confirm</Heading>
              <Card padding={24} radius="lg" border={true} style={{ background: 'var(--ggui-color-surfaceVariant)' }} shadow="none">
                <Stack gap="var(--ggui-spacing-4)">
                  <Stack direction="horizontal" justify="between"><Text>Name</Text><Text weight="bold">{formData.name}</Text></Stack>
                  <Stack direction="horizontal" justify="between"><Text>Email</Text><Text weight="bold">{formData.email}</Text></Stack>
                  <Stack direction="horizontal" justify="between"><Text>Role</Text><Text weight="bold">{formData.role}</Text></Stack>
                  <Stack direction="horizontal" justify="between"><Text>Notifications</Text><Text weight="bold">{formData.emailNotifications ? 'On' : 'Off'}</Text></Stack>
                  <Stack direction="horizontal" justify="between"><Text>Theme</Text><Text weight="bold">{formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'}</Text></Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Stack direction="horizontal" justify="between" style={{ marginTop: 'var(--ggui-spacing-6)' }}>
            <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={submit}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

