import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [addTaskColumns, setAddTaskColumns] = useState<Record<string, boolean>>({});
  const [addTaskTitle, setAddTaskTitle] = useState<Record<string, string>>({});
  const [addTaskPriority, setAddTaskPriority] = useState<Record<string, string>>({});

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof props.tasks> = {};
    props.columns?.forEach(col => {
      grouped[col.id || ''] = [];
    });
    props.tasks?.forEach(task => {
      const colId = task.column || '';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [props.tasks, props.columns]);

  const totalTasks = props.tasks?.length || 0;
  const completedTasks = tasksByColumn[props.columns?.[2]?.id || '']?.length || 0;

  const startEditing = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditValue(currentTitle || '');
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    const task = props.tasks?.find(t => t.id === taskId);
    if (task && editValue.trim()) {
      handleTaskUpdate({ ...task, title: editValue.trim() });
    }
    setEditingTaskId(null);
    setEditValue('');
  }, [props.tasks, editValue, handleTaskUpdate]);

  const moveTask = useCallback((taskId: string, newColumnId: string) => {
    const task = props.tasks?.find(t => t.id === taskId);
    if (task) {
      handleTaskUpdate({ ...task, column: newColumnId });
    }
  }, [props.tasks, handleTaskUpdate]);

  const addTask = useCallback((columnId: string) => {
    const title = addTaskTitle[columnId];
    const priority = addTaskPriority[columnId] || 'low';
    if (title?.trim()) {
      handleTaskUpdate({
        id: `task-${Date.now()}`,
        title: title.trim(),
        priority,
        column: columnId,
      });
      setAddTaskTitle(prev => ({ ...prev, [columnId]: '' }));
      setAddTaskPriority(prev => ({ ...prev, [columnId]: 'low' }));
      setAddTaskColumns(prev => ({ ...prev, [columnId]: false }));
    }
  }, [addTaskTitle, addTaskPriority, handleTaskUpdate]);

  const deleteTask = useCallback((taskId: string) => {
    const task = props.tasks?.find(t => t.id === taskId);
    if (task) {
      handleTaskUpdate({ ...task, _deleted: true });
    }
  }, [props.tasks, handleTaskUpdate]);

  return {
    editingTaskId,
    editValue,
    setEditValue,
    addTaskColumns,
    setAddTaskColumns,
    addTaskTitle,
    setAddTaskTitle,
    addTaskPriority,
    setAddTaskPriority,
    tasksByColumn,
    totalTasks,
    completedTasks,
    startEditing,
    saveEdit,
    moveTask,
    addTask,
    deleteTask,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'low':
        return 'success';
      case 'medium':
        return 'warning';
      case 'high':
        return 'error';
      default:
        return 'default';
    }
  };

  const getOtherColumns = (currentColumnId: string) => {
    return props.columns?.filter(col => col.id !== currentColumnId) || [];
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16}>
        {/* Summary Bar */}
        <Box style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
            <strong>{state.totalTasks}</strong> tasks
          </Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {state.completedTasks} completed
          </Text>
        </Box>

        <Divider orientation="horizontal" margin={0} />

        {/* Kanban Board */}
        <Stack direction="horizontal" gap={16} align="start" style={{ minHeight: '500px' }}>
          {props.columns?.map(column => (
            <Card key={column.id} shadow="sm" padding={16} style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
              {/* Column Header */}
              <Stack direction="horizontal" justify="between" align="center" gap={8} style={{ marginBottom: 12 }}>
                <Heading level={6} color="var(--ggui-color-onSurface, #18181b)">
                  {column.name}
                </Heading>
                <Badge variant="secondary" size="sm">
                  {state.tasksByColumn[column.id || '']?.length || 0}
                </Badge>
              </Stack>

              <Divider orientation="horizontal" margin={8} />

              {/* Tasks List */}
              <Stack gap={8} style={{ flex: 1, overflowY: 'auto', marginBottom: 12 }}>
                {state.tasksByColumn[column.id || '']?.map((task: typeof props.tasks[0]) => (
                  <Card key={task.id} shadow="sm" padding={12} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
                    {/* Task Title */}
                    {state.editingTaskId === task.id ? (
                      <Input
                         label="Edit task title"
                        value={state.editValue}
                        onChange={state.setEditValue}
                        onBlur={() => state.saveEdit(task.id || '')}
                        autoFocus
                        size="sm"
                        style={{ marginBottom: 8 }}
                      />
                    ) : (
                      <Stack direction="horizontal" justify="between" align="center" gap={4} style={{ marginBottom: 8 }}>
                        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" truncate>
                          {task.title}
                        </Text>
                        <Button
                          size="xs"
                          variant="ghost"
                          onClick={() => state.startEditing(task.id || '', task.title || '')}
                        >
                          ✎
                        </Button>
                      </Stack>
                    )}

                    {/* Task Metadata */}
                    <Stack direction="horizontal" align="center" gap={8} style={{ marginBottom: 8 }}>
                      <Badge variant={getPriorityColor(task.priority || 'low')} size="sm">
                        {task.priority || 'low'}
                      </Badge>
                      {task.assignee && (
                        <Avatar name={task.assignee} size="xs" />
                      )}
                      {task.dueDate && (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {task.dueDate}
                        </Text>
                      )}
                    </Stack>

                    {/* Move & Delete */}
                    <Stack direction="horizontal" gap={4}>
                      <Dropdown
                        trigger={<Button size="xs" variant="outline">Move</Button>}
                        options={getOtherColumns(column.id || '').map(col => ({
                          value: col.id || '',
                          label: col.name || '',
                        }))}
                        value=""
                        onChange={(val) => state.moveTask(task.id || '', val)}
                        placement="bottom-start"
                      />
                      <Button
                        size="xs"
                        variant="ghost"
                        onClick={() => state.deleteTask(task.id || '')}
                      >
                        🗑
                      </Button>
                    </Stack>
                  </Card>
                ))}
              </Stack>

              {/* Add Task Form */}
              {state.addTaskColumns[column.id || ''] ? (
                <Stack gap={8} style={{ padding: 8, backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
                  <Input
                     label="Task title"
                    placeholder="Task title..."
                    value={state.addTaskTitle[column.id || ''] || ''}
                    onChange={(val) => state.setAddTaskTitle(prev => ({ ...prev, [column.id || '']: val }))}
                    size="sm"
                  />
                  <Select
                     label="Priority"
                    value={state.addTaskPriority[column.id || ''] || 'low'}
                    onChange={(val) => state.setAddTaskPriority(prev => ({ ...prev, [column.id || '']: val }))}
                    options={[
                      { value: 'low', label: 'Low' },
                      { value: 'medium', label: 'Medium' },
                      { value: 'high', label: 'High' },
                    ]}
                    size="sm"
                  />
                  <Stack direction="horizontal" gap={4}>
                    <Button
                      size="sm"
                      variant="primary"
                      fullWidth
                      onClick={() => state.addTask(column.id || '')}
                    >
                      Create
                    </Button>
                    <Button
                      size="sm"
                      variant="ghost"
                      onClick={() => state.setAddTaskColumns(prev => ({ ...prev, [column.id || '']: false }))}
                    >
                      Cancel
                    </Button>
                  </Stack>
                </Stack>
              ) : (
                <Button
                  variant="ghost"
                  fullWidth
                  onClick={() => state.setAddTaskColumns(prev => ({ ...prev, [column.id || '']: true }))}
                >
                  + Add Task
                </Button>
              )}
            </Card>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

