    'alkaline-earth-metal': 'var(--ggui-color-error-900, #7f1d1d)',
    'transition-metal': 'var(--ggui-color-info-900, #164e63)',
    'lanthanide': 'var(--ggui-color-primary-900, #0c4a6e)',
    'actinide': 'var(--ggui-color-onSurfaceVariant, #52525b)',
    'halogen': 'var(--ggui-color-container, #4c1d95)',
    'metalloid': 'var(--ggui-color-primary-900, #0c4a6e)',
    'post-transition-metal': 'var(--ggui-color-onSurfaceVariant, #52525b)',
  }), []);

  const handleElementClick = useCallback((element: typeof props.elements[0]) => {
    setSelectedElement(element);
  }, []);

  const handleElementKeyDown = useCallback((e: React.KeyboardEvent, element: typeof props.elements[0]) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      setSelectedElement(element);
    } else if (e.key === 'Escape' && selectedElement) {
      e.preventDefault();
      setSelectedElement(null);
    }
  }, [selectedElement]);

  const handleCloseDetail = useCallback(() => {
    setSelectedElement(null);
  }, []);

  const handleSearch = useCallback((value: string) => {
    setSearchQuery(value);
  }, []);

  return {
    searchQuery,
    handleSearch,
    filteredElements,
    selectedElement,
    handleElementClick,
    handleCloseDetail,
    handleElementKeyDown,
    categories,
    categoryColorMap,
    categoryTextColorMap,
  };
}

