  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  // TODO: add state and computed values
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const [isAdding, setIsAdding] = useState(false);

  const product = props.product || {};
  const stock = product.stock ?? 0;
  const rating = product.rating ?? 0;
  const specifications = (product.specifications || []) as Array<{ key: string; value: string }>;
  const reviews = (product.reviews || []) as Array<{ author: string; rating: number; text: string; date: string }>;

  const handleQuantityChange = useCallback((value: number) => {
    const clamped = Math.max(1, Math.min(value, stock));
    setQuantity(clamped);
  }, [stock]);

  const handleAddClick = useCallback(async () => {
    setIsAdding(true);
    try {
      await handleAddToCart({ productId: product.id, quantity });
    } finally {
      setIsAdding(false);
    }
  }, [product.id, quantity, handleAddToCart]);

  const isOutOfStock = stock === 0;
  const isLowStock = stock > 0 && stock < 5;
  const stockBadgeVariant: 'error' | 'warning' | 'success' | 'primary' | 'secondary' | 'default' | 'info' = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';
  const stockLabel = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';

  const tabItems = [
