        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available.</Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: reviews.length > 0 ? (
        <Stack gap={16}>
          {reviews.map((review, idx) => (
            <Card key={idx} padding={16} shadow="sm">
              <Stack gap={8}>
                <Stack direction="horizontal" gap={12} align="center">
                  <Text weight="semibold">{review.author || 'Anonymous'}</Text>
                  <Stack direction="horizontal" gap={4}>
                    {Array.from({ length: 5 }).map((_, i) => (
                      <Icon
                        key={i}
                        name={i < (review.rating || 0) ? 'star' : 'star'}
                        size={16}
                        color={i < (review.rating || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outlineVariant, #e4e4e7)'}
                      />
                    ))}
                  </Stack>
                </Stack>
                <Text variant="body">{review.text || ''}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {review.date ? new Date(review.date).toLocaleDateString() : 'Date unknown'}
                </Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>
      ),
    },
  ];

  return { quantity, activeTab, setActiveTab, handleQuantityChange, handleAddClick, isAdding, isOutOfStock, stock, rating, stockBadgeVariant, stockLabel, tabItems };
}

