                  >
                    {msg.text}
                  </Text>
                  <time
                    dateTime={msg.timestamp}
                    style={{
                      display: 'block',
                      marginTop: 'var(--ggui-spacing-1, 4px)',
                      color: isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                    }}
                  >
                    {state.formatTimestamp(msg.timestamp)}
                  </time>
                </Box>
              ))}
            </Stack>
          );
        })}
        <div ref={state.messagesEndRef} />
      </Box>

      {/* Input Area */}
      <Box
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
