            onKeyDown={state.onInputKeyDown}
            style={{
              flex: 1,
            }}
          />
          <Button
            variant="primary"
            onClick={state.onSendClick}
            disabled={!state.inputValue.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Box>
  );
